"""
MKT Context Commentary — Deuteronomy 14–17 (94 verses)
Run: python3 scripts/zc-context-deuteronomy-14-17.py

Source data used:
- data/interlinear/deuteronomy.json
- data/translation/glossary-hebrew.json (key terms)
- data/translation/draft/mediating/deuteronomy.json (MKT text)

Key decisions:
- Ch 14 dietary laws: use Mary Douglas's anthropological analysis alongside
  archaeological data (pig-bone absence from Israelite sites); note kid-in-milk
  as basis for meat/dairy separation
- Ch 15 Shemita: contrast with ANE misharum decrees; quote Jesus (Mark 14:7)
  on the poor-always-with-you tension
- Ch 16 three feasts: note their agricultural grounding; Pentecost's Sinai-anniversary
  interpretation as background for Acts 2; John 7 Tabernacles context
- Ch 17 king-law: systematic comparison with Solomon's failures; ANE contrast
  (no parallel anti-luxury king-law in surrounding cultures)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


DEUT = {
    "14": {
        "1": "<p>\"You are the children of the LORD your God. You shall not gash yourselves or shave the front of your head in mourning for the dead\" — the prohibition of self-laceration (<em>lo titgodedu</em>) and front-shaving in mourning: both practices are attested in the Ugaritic texts as components of Canaanite mourning ritual. The Baal Cycle describes El and Baal's companions cutting themselves and shaving in grief. The priests of Baal on Carmel cut themselves with swords and spears in worship-ecstasy (1 Kgs 18:28). Jeremiah 16:6 records these practices as ones Israel was prone to adopt from its neighbors. The prohibition is grounded not merely in cultural distinction but in identity: Israel is YHWH's children (<em>banim atem lYHWH eloheichem</em>), and children of the living God do not employ the mourning rites of those who serve dead or dying deities.</p>",
        "2": "<p>\"For you are a people holy to the LORD your God, and the LORD has chosen you to be his treasured possession from all the peoples on the face of the earth\" — the election-basis repeated from 7:6: the dietary and mourning regulations are not arbitrary cultural markers but expressions of the covenant identity. The holiness (<em>am qadosh</em>) and treasured-possession (<em>am segulah</em>) language grounds every regulation that follows in the character of the relationship, not in the rules themselves. Deuteronomy's ethical logic runs consistently from identity to behavior: because you are who you are, do what you do.</p>",
        "3": "<p>\"You shall not eat any detestable thing (<em>toevah</em>)\" — the summary principle before the list: <em>toevah</em> (H8441) is the strongest term of religious and moral aversion in the OT, used for idolatry, sexual offenses, and cultic violations. The dietary prohibitions are thus framed as matters of holiness and covenant loyalty, not mere hygiene. The application of <em>toevah</em> to food establishes that the dietary laws are not a health code but a boundary-marking system that defines Israel as YHWH's covenant people within its polytheistic environment.</p>",
        "4": "<p>\"These are the animals you may eat: the ox, the sheep, and the goat\" — the permitted domestic animals: the three foundational livestock of the ancient Levantine economy. All three were also primary sacrificial animals — the criteria for clean animals align with what YHWH accepts at the altar. The Israelite diet and the Israelite sacrificial system use the same species: what is clean for the table is what is clean for the altar.</p>",
        "5": "<p>\"The deer, the gazelle, the roe deer, the wild goat, the ibex, the antelope, and the mountain sheep\" — the seven clean wild game animals: all are hunted animals of the highland region of Canaan and Transjordan, documented in archaeological faunal remains from Israelite sites. Their inclusion alongside domestic livestock reflects the economic life of an agricultural-pastoral society that also hunted. All share the clean-animal criteria: divided hoof and chewing of cud.</p>",
        "6": "<p>\"You may eat any animal that has completely split hooves and chews the cud\" — the two-criterion rule for permitted land animals: the split-hoof/cud-chewing combination is a natural grouping of ruminant herbivores (cattle, sheep, goats, deer, etc.). Mary Douglas's anthropological analysis (<em>Purity and Danger</em>, 1966) argues that the clean/unclean system reflects a coherent taxonomy: clean animals are those that belong unambiguously to their category (walking on split hooves; grazing by chewing cud), while anomalies — creatures that fulfill one criterion but not the other — are unclean because they violate category integrity. The system encodes holiness as wholeness: each creature should conform fully to its type.</p>",
        "7": "<p>\"However, among those that chew the cud or have split hooves, these you shall not eat: the camel, the hare, and the rock badger\" — the boundary cases: the camel, hare, and rock badger appear to chew cud but lack fully divided hooves. Strictly speaking, hares (<em>shafan</em>, H8227) engage in cecotrophy (consuming their own droppings for nutrition) which was described as cud-chewing by ancient observers. The camel has padded feet rather than split hooves. These are the anomaly cases that define the edges of the clean category — they are excluded precisely because they fit one criterion but not both, making them boundary-blurring anomalies.</p>",
        "8": "<p>\"And the pig — though it has split hooves, it does not chew the cud. It is unclean for you. You shall not eat their meat or touch their carcasses\" — the pig prohibition is the most archaeologically significant of the dietary laws: faunal analyses of Iron Age (ca. 1200-586 BCE) sites in the central highlands of Canaan show a striking absence of pig bones at sites identified as Israelite versus Philistine or Canaanite sites (Elizabeth Bloch-Smith, Israel Finkelstein, and others). The absence of pig bones is one of the most reliable indicators of Israelite cultural identity in the archaeological record. The pig raised and eaten by everyone around Israel became one of Israel's most distinctive self-defining prohibitions.</p>",
        "9": "<p>\"Of all creatures living in the water, you may eat those that have fins and scales\" — the two-criterion rule for aquatic creatures: fins and scales. Fish with both (all the common food fish of the Sea of Galilee and Mediterranean) are clean; shellfish, crustaceans, eels, and scaleless fish are not. The Galilean fishing economy was largely built on clean fish (tilapia, carp). The prohibition of shellfish was economically significant in coastal and inland water communities — oysters, shrimp, lobster, and similar items that were delicacies in Egyptian and Mediterranean cuisine were excluded from the Israelite table.</p>",
        "10": "<p>\"But whatever lacks fins or scales you shall not eat; it is unclean for you\" — the negative application of the water-creature rule. Douglas's analysis again: creatures that swim without fins and scales (eels, jellyfish) are anomalies in the aquatic category — they don't fit the normal mode of aquatic movement. Their exclusion maintains the category integrity of the system.</p>",
        "11": "<p>\"You may eat any clean bird\" — the positive rule for birds is not accompanied by criteria (unlike land animals and water creatures). Instead, Deuteronomy provides a list of prohibited birds, implying the default for birds is clean unless specified otherwise. The permitted clean birds include the common food birds of the Levant: pigeons, doves, quail, sparrows.</p>",
        "12": "<p>\"These are the birds you shall not eat: the eagle, the bearded vulture, and the black vulture\" — the list of twenty prohibited birds (vv12-18) consists primarily of raptors and carrion-eaters. The eagle (<em>nesher</em>, H5404 — likely including vultures), bearded vulture (<em>peres</em>, H6538), and black vulture (<em>ozniyah</em>, H5822) are at the top of the avian predator hierarchy. The unifying characteristic of the prohibited birds appears to be raptor or scavenger status — they eat blood and flesh directly. The logic may be that clean birds eat vegetation or grain, while unclean birds consume other creatures' blood, and Israel is a people for whom blood is sacred (Deut 12:16,23: the blood is the life).</p>",
        "13": "<p>\"The kite and any kind of falcon\" — the falcons (<em>dayyah</em>, H1676; <em>ayyah</em>, H344) and kites are raptors that hunt and kill. The phrase \"any kind of\" indicates species-groups rather than individual species — the prohibition covers the entire raptor family, not merely those precisely identifiable by name.</p>",
        "14": "<p>\"Every kind of raven\" — the raven (<em>orev</em>, H6158) appears prominently in biblical narrative: ravens fed Elijah (1 Kgs 17:4-6); Noah sent a raven first from the ark (Gen 8:7). Despite the raven's narrative significance, it remains on the prohibited list. Its exclusion is likely due to its omnivorous scavenging behavior (eating carrion). The \"every kind of\" formula again indicates a family-level prohibition.</p>",
        "15": "<p>\"The ostrich, the nighthawk, the sea gull, and every kind of hawk\" — these birds (v15 through v18) complete the list of prohibited species. The ostrich (<em>bat hayanah</em>, H1323+3284) was exotic and rare in Canaan; its flesh was not a typical food item. The nighthawk (or owl, <em>tachmas</em>, H8464) and sea gull (<em>shachaf</em>, H7828) are water-coastal birds whose precise identification is debated. The hawk family (<em>netz</em>, H5322) is a broad raptor category.</p>",
        "16": "<p>\"The little owl, the screech owl, and the barn owl\" — three owl species: <em>kos</em> (H3563, little owl), <em>yanshuf</em> (H3244, barn owl or eagle owl), <em>tinshames</em> (H8580). The Hebrew terms for many of these birds are uncertain in precise species identification — the LXX translators showed uncertainty too. What is consistent is their nocturnal, predatory, or carrion-eating character. Owls hunt at night and eat small mammals — their association with desolation and death in OT poetry (Isa 13:21; 34:11; Ps 102:6) may also contribute to their excluded status.</p>",
        "17": "<p>\"The pelican, the carrion vulture, and the cormorant\" — the pelican (<em>qaah</em>, H6893), the carrion vulture or osprey (<em>racham</em>, H7360), and the cormorant (<em>shalach</em>, H7994) complete the water-birds group. All three associate with water environments and consume fish or carrion. The cormorant's diving-and-catching behavior made it unclean by association with water creatures without fins or scales (eating them makes the bird itself boundary-transgressive).</p>",
        "18": "<p>\"The stork, any kind of heron, the hoopoe, and the bat\" — the stork (<em>chasidah</em>, H2624 — whose name shares the root of <em>chesed</em>, loyal-love, giving it a somewhat ironic placement in the unclean list) is a migratory bird well-attested in Canaan. The heron (<em>anafah</em>, H601) and hoopoe (<em>duchifat</em>, H1744 — Solomon's messenger bird in later legend) complete the list. The bat (<em>atalef</em>, H5847) is classified with birds in the Israelite taxonomy (as it was in most ancient taxonomies before modern biology) but clearly crosses the bird-land-creature boundary in having both wings and fur. Bats eat flying insects — themselves unclean (v19). The taxonomic anomaly places them in the prohibited category.</p>",
        "19": "<p>\"All winged insects are unclean for you; they shall not be eaten\" — the prohibition on flying insects (<em>sheretz ha'of</em>) as a class. Leviticus 11:20-23 adds the exception of four-legged locusts — insects with jumping legs (locusts, grasshoppers, crickets) are clean. The Deuteronomy version states the general rule without the exception. Locusts were a significant food source in the ancient Near East (John the Baptist ate locusts and wild honey, Mark 1:6) and were consumed throughout the region. Their permitted status reflects the anomaly-exception: they fly (normally unclean for insects) but they also hop like land creatures (partially fitting the land-animal mode).</p>",
        "20": "<p>\"But all clean birds you may eat\" — the positive summary balancing v19: after the prohibitions, the default is restated. The dietary system is not primarily prohibitive but defines a large category of permitted foods with a bounded set of exceptions. The pedagogical function: in a world saturated with cultic food practices (animals sacrificed to idols were the primary meat source for most ANE peoples), Israel's dietary boundaries created a daily practice of covenant consciousness at the table.</p>",
        "21": "<p>\"You shall not eat anything that dies of itself. You may give it to the foreigner living in your town to eat, or you may sell it to a foreigner\" — the prohibition of eating animals that die naturally (<em>nevela</em>, H5038): an animal that dies without proper ritual slaughter retains its blood within its flesh (since the blood was not drained at death). Israel's covenant with YHWH includes the blood-respect principle (Deut 12:23: the blood is the life). A foreigner (<em>ger</em>, resident alien) or non-Israelite sojourner (<em>nokri</em>) does not share this covenant obligation — the prohibition is covenant-specific, not universal. \"For you are a people holy to the LORD your God\" closes the verse, restating the identity-basis for the dietary system. The concluding sub-rule: \"You shall not boil a young goat in its mother's milk\" — the origin of the meat-dairy separation in Jewish practice (three times in Torah: Exod 23:19; 34:26; Deut 14:21). Canaanite cultic texts from Ugarit (KTU 1.23) mention cooking a kid in milk as a possible fertility-cult practice; the prohibition may target specifically this cultic act.</p>",
        "22": "<p>\"You shall tithe all the yield of your seed that comes from the field each year\" — the annual tithe regulation (vv22-27): 10% of the year's agricultural produce is brought to the central sanctuary for consumption in YHWH's presence. The tithe system is well-attested in ANE contexts — Mesopotamian temples collected tithes from the agricultural produce of their regions. Deuteronomy's tithe differs in its purpose: not primarily to support the temple institution but to train covenant piety (v23: \"so that you may learn to fear the LORD your God always\"). The tithe is a vehicle for teaching, not merely support.</p>",
        "23": "<p>\"And in the presence of the LORD your God, at the place he will choose to make his name dwell, you shall eat the tithe of your grain, your wine, and your oil, and the firstborn of your herd and flock, so that you may learn to fear the LORD your God always\" — the communal meal as the tithe's goal: the produce is not merely donated but consumed at the sanctuary in covenant fellowship. This is celebratory theology — the tithe creates an annual feast in YHWH's presence. The purpose clause (<em>lemaan tilmad liyera YHWH eloheicha kol hayamim</em>) is remarkable: the tithe's goal is not fiscal but educational, the cultivation of awe before YHWH throughout one's life.</p>",
        "24": "<p>\"But if the distance is too great for you to carry the tithe\" — the concession for distance: the centralization of worship at a single sanctuary created a practical problem for those far from Jerusalem. The Deuteronomic solution is pragmatic: convert the tithe to silver (money), transport the lighter currency, and purchase equivalent goods at the destination. This is one of the earliest examples of economic reasoning within Torah law — the principle is preserved while the impractical physical requirement is adapted to circumstance.</p>",
        "25": "<p>\"Then you shall exchange the tithe for money, and take the money in hand to the place that the LORD your God will choose\" — the monetization of the tithe for long-distance transport: coinage did not exist in Israel until the Persian period; the \"money\" (<em>kessef</em>, silver) was weighed silver rather than coined. The ability to carry wealth as portable silver rather than bulk grain represented a significant economic adaptation. This passage implies a degree of market sophistication: tithe-producers could sell their produce locally, carry silver, and buy food-goods at the sanctuary.</p>",
        "26": "<p>\"And spend the money for whatever you desire — cattle, sheep, wine, strong drink, or whatever you want — and eat there before the LORD your God, and rejoice, you and your household\" — the explicit inclusion of <em>shechar</em> (strong drink, H7941 — beer, date wine, or similar fermented beverages) among the permitted tithe-feast purchases is notable: the tithe meal is a celebration, not an ascetic observance. The \"rejoice\" (<em>samach</em>, H8055) command appears repeatedly in the festival laws (Deut 12:7,12,18; 14:26; 16:11,14; 26:11; 27:7). Deuteronomy commands joy as covenant practice — the covenant meal is a celebration of YHWH's provision, not a solemn duty.</p>",
        "27": "<p>\"And do not neglect the Levite who lives in your towns, for he has no portion or inheritance among you\" — the Levite-care requirement interrupts the tithe-feast instruction: even in celebration, the community's responsibility for the Levites must not be forgotten. Levites received no land allotment (Josh 13:14) and were therefore economically dependent on the rest of Israel's covenant generosity. Their presence in \"your towns\" (<em>bishareikha</em>) — the Levitical cities — means they are part of every community's social fabric. The integration of celebration with social responsibility is characteristically Deuteronomic.</p>",
        "28": "<p>\"At the end of every three years you shall bring out all the tithe of your produce from that year and store it within your towns\" — the triennial tithe: a second tithe collected every third year and stored locally (rather than taken to the central sanctuary) for distribution to the Levites, resident aliens, orphans, and widows. Josephus (Antiquities 4.8.22) describes a three-tithe system in Second Temple Judaism: the first tithe to Levites, the second tithe for sanctuary meals (vv22-27), and the third tithe for the poor. Deuteronomy's social-welfare system is built into the agricultural economy's revenue stream — poverty relief is not an optional add-on but a mandatory allocation of the tithe cycle.</p>",
        "29": "<p>\"So that the Levite — who has no portion or inheritance among you — and the resident foreigner, the fatherless, and the widow within your towns may come and eat and be satisfied, and so that the LORD your God may bless you in all the work of your hands that you do\" — the four-group social safety net: Levites (no land), <em>ger</em> (resident aliens, no inherited rights), orphans (<em>yatom</em>), and widows (<em>almanah</em>) are the covenant community's designated vulnerable members who receive systematic provision through the triennial tithe. This quadruplet of protected groups appears throughout Deuteronomy (10:18; 16:11,14; 24:17,19-21; 26:12-13; 27:19) and runs through the Prophets (Jer 7:6; 22:3; Ezek 22:7; Zech 7:10; Mal 3:5). The blessing-motive at the end: generosity toward the vulnerable is itself the condition for YHWH's blessing on the giver's work.</p>"
    },
    "15": {
        "1": "<p>\"At the end of every seven years you shall grant a release (<em>shemita</em>)\" — the Sabbatical year debt-release (Shemita, H8058, from <em>shamat</em>, to release/remit): every seventh year all outstanding debts between Israelites are cancelled. No ANE parallel exists for a universal, systematically recurring debt-release built into national law. Mesopotamian kings occasionally declared <em>misharum</em> (equity) decrees that cancelled certain debts — but these were royal prerogatives, not legal institutions. The Babylonian <em>andurarum</em> edicts (debt-releases) were issued by kings for political benefit, not built into law as automatic annual events. The Shemita's legal institutionalization is unique in the ancient world.</p>",
        "2": "<p>\"And this is how the release shall work: every creditor shall cancel what he has lent to his neighbor. He must not press his neighbor or his brother, for the LORD's release has been proclaimed\" — the Shemita is called \"the LORD's release\" (<em>shemitat YHWH</em>): debt-release is YHWH's action, not merely a human economic policy. The framing prevents the release from being seen as a human concession — it is the covenant community's recognition that YHWH's ownership of the land (Lev 25:23: \"the land is mine\") means that perpetual debt-bondage is incompatible with covenant status. Every seventh year the land's ownership-structure is reset toward the ideal of Israelite independence.</p>",
        "3": "<p>\"You may collect from a foreigner, but whatever your brother owes you, you must release\" — the insider-outsider distinction: the Shemita applies only within the covenant community (\"brother,\" <em>ach</em>). Foreigners (<em>nokri</em>) engaging in commercial trade with Israelites are not party to the covenant's debt-release provisions. This reflects the covenant's relational logic: the Shemita expresses YHWH's care for his own people; it does not reorganize all economic relationships in the world. The NT extends the principle: Jesus's command to forgive as we have been forgiven (Matt 6:12) applies the covenant-release logic to all relationships without the ethnic boundary.</p>",
        "4": "<p>\"There need be no poor among you, for the LORD will surely bless you in the land that the LORD your God is giving you as an inheritance to possess\" — the ideal: if the Shemita is faithfully practiced along with the other covenant laws, the structural conditions for poverty are eliminated. This is not a naive claim that poverty can be eliminated by decree, but a covenant-structural argument: a system with regular debt-release, triennial poor-tithe, gleaning laws, and Jubilee land-return is a system designed to prevent the accumulation of permanent underclasses. Compare v11: \"there will never cease to be poor people in the land\" — the realistic expectation given human failure to keep the law. The tension between vv4 and 11 is the tension between covenant ideal and covenant reality, not a textual contradiction.</p>",
        "5": "<p>\"If only you carefully obey the voice of the LORD your God, being diligent to keep all this commandment that I am commanding you today\" — the conditional: the promise of v4 (no poor) is conditioned on comprehensive covenant faithfulness. The \"if only\" (<em>raq</em> + conditional) marks this as an ideal dependent on full obedience — which Deuteronomy knows will not be achieved (29:4; 30:1-5 already anticipate disobedience and exile). The promises of the covenant are structurally genuine but practically contingent on human faithfulness that history will show is unavailable without the new heart promised in 30:6 and Jer 31:33.</p>",
        "6": "<p>\"For the LORD your God will bless you as he has promised, and you will lend to many nations but not borrow, and you will rule over many nations but they will not rule over you\" — the international economic reversal: covenant blessing transforms Israel from a borrower-nation (slave in Egypt; borrowers from Egypt) to a lender-nation whose surplus funds other economies. Proverbs 22:7 (\"the borrower is slave to the lender\") captures the power-dynamic at stake: covenant faithfulness produces the economic dominance that the Exodus was designed to reverse. The promise is stated as certainty conditioned on the \"if\" of v5.</p>",
        "7": "<p>\"If there is a poor person among you, one of your brothers, in any of your towns in the land that the LORD your God is giving you, you shall not harden your heart or close your hand against your poor brother\" — the pastoral application of the Shemita's spirit: the law's institutional framework (Shemita, triennial tithe) does not exhaust the covenant's demand. Even between Shemita years, the poor must not be ignored. The two metaphors — hard heart (<em>kavad levavecha</em>) and closed hand (<em>qafatz yadecha</em>) — name the twin failures of covenant generosity: emotional callousness and economic withholding. The covenant person must be both moved and acting.</p>",
        "8": "<p>\"Instead, you shall open your hand wide to him and lend him whatever he needs, enough for his lack\" — the open-hand imperative (<em>patoach tiftach et yadecha</em>): the doubled verbal construction intensifies the command — \"opening you shall open.\" The loan is calculated not on the lender's convenience but on the borrower's need (<em>dei machsoro</em>, \"enough for his lack\"). The need-based standard for lending is a striking inversion of normal commercial logic: the lender's return calculation is replaced by the borrower's need calculation as the governing criterion.</p>",
        "9": "<p>\"Guard against an unworthy thought in your heart: 'The seventh year, the year of release, is near,' so that you look with hostility on your poor brother and give him nothing\" — the predatory rationalization: as the Shemita year approached, lenders might refuse new loans knowing they would be cancelled soon. The Torah anticipates and prohibits this rational economic calculation when it conflicts with covenant generosity. The \"unworthy thought\" (<em>davar beliyaal</em>) — literally a word of worthlessness/destruction — is a sinful calculation in the heart (<em>levavecha</em>) that produces stingy behavior. YHWH's judgment (<em>vekara eleicha el YHWH veheya vecha chet</em>) tracks the heart's motive, not just the external act.</p>",
        "10": "<p>\"Give to him generously, and do not be reluctant when you give, for because of this the LORD your God will bless you in all your work and in all that you undertake\" — the motivational link between generosity and blessing: Deuteronomy's economic theology consistently connects covenant generosity with divine provision. This is not prosperity-gospel transactionalism (give to get) but covenant-structure: YHWH blesses the community that maintains the covenant's social structure. Generosity toward the poor is the maintenance of the community's covenant integrity, and YHWH's blessing upon work (<em>bemaaseh yadecha ubechol mishlach yadecha</em>) is the covenant community's thriving.</p>",
        "11": "<p>\"For there will never cease to be poor people in the land. That is why I am commanding you to open your hand wide to your brother — to your poor and needy in the land\" — the realistic permanent-poverty statement: v4 (there need be no poor) and v11 (there will always be poor) are not contradictory but operate at different registers. V4 describes what the covenant structure would produce if perfectly followed; v11 acknowledges the permanent reality of human failure to follow the covenant perfectly. Jesus quotes v11 in Mark 14:7 (\"the poor you always have with you\") — not to limit generosity but to argue that the permanent reality of poverty does not make specific acts of generosity toward him inappropriate. The argument is about priority in a moment, not dismissal of poverty's permanence.</p>",
        "12": "<p>\"If your brother, a Hebrew man or a Hebrew woman, is sold to you and serves you six years, then in the seventh year you shall set him free from you\" — the Shemita's application to enslaved persons: the parallel to Exod 21:1-6 (the Covenant Code's slave release law) with the addition of \"or a Hebrew woman\" — Deuteronomy explicitly includes women in the six-year service and release provisions. In Exod 21:2-6, the woman's release is not explicitly stated in the same terms. Deuteronomy's expansion of the law's gender inclusion is one of its characteristic progressive-law features: what was implied or assumed is made explicit and equal.</p>",
        "13": "<p>\"And when you set him free, you shall not send him away empty-handed\" — the sending-away provision: the released slave must not exit with nothing. The empty-handed departure (<em>reiqam</em>) would replicate the slave-status economically even after formal freedom. The purpose of the release is actual restoration to independent-viable status, not merely legal manumission. The principle echoes the Exodus itself: \"and the LORD had given the people favor in the sight of the Egyptians, so that they let them have what they asked. Thus they plundered the Egyptians\" (Exod 12:36) — Israel left Egypt with resources, not empty-handed.</p>",
        "14": "<p>\"You shall supply him generously from your flock, your threshing floor, and your winepress. Give to him as the LORD your God has blessed you\" — the graduated generosity: the master's provision for the released slave is proportional to YHWH's blessing on the master. The formula \"as the LORD has blessed you\" (<em>keasher berach-cha YHWH eloheicha</em>) appears throughout the giving-laws of Deuteronomy (16:10,17; 26:15) — the measure of giving is the measure of receiving. The slave-release becomes a redistribution of YHWH's blessing from the more-blessed to the less-blessed, maintaining the covenant community's economic solidarity.</p>",
        "15": "<p>\"Remember that you were a slave in Egypt, and the LORD your God redeemed you\" — the Exodus-memory as the motive for slave-release: the most powerful argument in Deuteronomy's ethics is the memory of one's own vulnerability. Those who were slaves cannot legitimately maintain permanent slavery without internal contradiction of their own identity as redeemed people. Leviticus 25:42 makes the same argument: \"For they are my servants, whom I brought out of the land of Egypt; they shall not be sold as slaves.\" Israel is YHWH's servant; no Israelite can be another Israelite's permanent slave because prior ownership is already claimed.</p>",
        "16": "<p>\"But if the servant says to you, 'I do not want to leave you,' because he loves you and your household and is well-off with you\" — the voluntary permanent servanthood: the slave who chooses to remain because of genuine relational and economic contentment is not compelled to leave. The ground given (\"loves you and your household\") presents this as a relationship-choice, not a fear-based or economically-coerced decision. The voluntary servant creates a household relationship that transcends formal economic contract — an unusual recognition in ancient legal contexts of relational motivation as a legitimate basis for legal status.</p>",
        "17": "<p>\"Then you shall take an awl and pierce his ear against the door, and he shall be your servant permanently\" — the ear-piercing ceremony marks the voluntary transition to permanent household membership. The door (<em>delet</em>) is the threshold of the house — the servant is incorporated into the household at its boundary, becoming permanently part of it. The practice is attested in Exod 21:6 (\"at the door\" or \"at the doorpost\") and appears in Mesopotamian slave-freedom and voluntary re-enslavement documents. The ear as the organ of covenant-hearing (the ear hears and obeys the master's voice) is the appropriate site for the mark of permanent service.</p>",
        "18": "<p>\"Do not find it difficult when you set him free, for he has served you six years at half the cost of a hired worker\" — the economic argument against reluctance: a six-year servant has worked for approximately half what a free hired laborer would have cost (since a hired worker might be employed only when needed while the servant is available year-round). The master has received more than fair value from six years of service. The Torah addresses the potential reluctance of masters to release valuable servants by noting the economic benefit already received — the release is not a sacrifice but a fair conclusion to an economically beneficial arrangement.</p>",
        "19": "<p>\"You shall set apart for the LORD your God every firstborn male born of your herd and your flock. You shall not put the firstborn of your oxen to work, nor shear the firstborn of your flock\" — the firstborn animal law: the firstborn of livestock belongs to YHWH as a claim on the first-fruits of life. The practical expression: the firstborn ox is not put to agricultural work (not draft-worked) and the firstborn sheep is not shorn for wool — their products are not exploited commercially. They are held apart for YHWH. The firstborn theology runs from the Passover (YHWH's claim on Egypt's firstborn; the substitutionary redemption of Israel's firstborn, Exod 13:1-16) through the NT (Christ as the \"firstborn among many brothers,\" Rom 8:29; the \"firstborn of all creation,\" Col 1:15).</p>",
        "20": "<p>\"Year by year you shall eat it before the LORD your God at the place the LORD will choose — you and your household\" — the firstborn animal is consumed in a sanctuary meal rather than sacrificed in the atoning sense: it is a covenant feast. The annual repetition of this feast (\"year by year\") at the central sanctuary ties the agricultural calendar to covenant celebration. Every year, the best of the flock is brought to YHWH's presence and shared in his presence — a sustained liturgical practice of acknowledging YHWH's ownership of the firstfruits of life.</p>",
        "21": "<p>\"But if it has any defect — if it is lame or blind or has any serious flaw — you do not sacrifice it to the LORD your God\" — the unblemished requirement: a defective animal is not presented to YHWH, consistent with the principle of Deut 17:1 and the broader cultic standard that the gift must match the giver's honor. Presenting a defective animal would be analogous to offering God one's worthless surplus rather than one's best. Malachi 1:8 indicts post-exilic Israel for exactly this: \"When you offer blind animals in sacrifice, is that not evil? And when you offer those that are lame or sick, is that not evil? Present that to your governor; will he accept you or show you favor?\"</p>",
        "22": "<p>\"You shall eat it within your own towns — the ceremonially unclean and the clean may eat it alike, just as you would eat a gazelle or a deer\" — the defective firstborn is consumed locally rather than at the central sanctuary, and the normal purity requirements for sanctuary eating (levitical cleanness) do not apply. The comparison to gazelle and deer (which are hunted rather than sacrificed) signals its status as ordinary meat rather than sacred feast. The clean/unclean distinction that governs sanctuary meals does not apply to this local consumption — a significant simplification for families managing livestock in remote areas.</p>",
        "23": "<p>\"Only do not eat its blood; pour it out on the ground like water\" — the blood-pouring law applies even to defective firstborn eaten locally: regardless of context, the blood must not be eaten but poured out on the ground. The ground-pouring (rather than the altar-pouring of sacrificed animals) is the lay-person's equivalent of the priest's blood-ritual — it returns the life (<em>nefesh</em>) to the earth from which the animal came. The blood-prohibition is the one dietary law that admits no exceptions in any context, because it expresses the most fundamental theological principle of Israel's food ethics: life belongs to God.</p>"
    },
    "16": {
        "1": "<p>\"Observe the month of Abib and celebrate the Passover to the LORD your God, for in the month of Abib the LORD your God brought you out of Egypt by night\" — Abib (H24, later called Nisan) is the first month of the Hebrew religious calendar, corresponding to March-April. \"Abib\" means \"ear of grain\" — the new-grain month, when barley begins to ripen. The name encodes the agricultural cycle into the calendar: Israel's liberation-event falls in the agricultural year's first month, tying covenant history to creation's rhythms. The Passover's centralization at the chosen sanctuary (v2) reflects the Deuteronomic reform program's consolidation of worship — historically, Passover was a household observance (Exod 12:3-7); the centralization is a significant institutional development completed under Josiah (2 Kgs 23:21-23).</p>",
        "2": "<p>\"You shall sacrifice the Passover offering to the LORD your God — from the flock or the herd — at the place the LORD will choose to make his name dwell\" — the inclusion of cattle (<em>baqar</em>) in addition to sheep and goats expands the Passover offering beyond Exodus 12's lamb-only provision. This may reflect the Passover's growth into a larger communal celebration at the central sanctuary where a single household's lamb would be inadequate for pilgrimage crowds. The \"place the LORD will choose\" (<em>maaqom asher yivchar YHWH</em>) is Deuteronomy's persistent formula for Jerusalem (the specific name is never given in Deuteronomy — the later Deuteronomistic History identifies it retroactively).</p>",
        "3": "<p>\"You shall eat no leavened bread with it. For seven days you shall eat unleavened bread — the bread of affliction (<em>lechem oni</em>) — because you left the land of Egypt in haste\" — the Feast of Unleavened Bread immediately follows and overlaps with Passover in Deuteronomy's presentation. The \"bread of affliction\" (<em>lechem oni</em>) names the unleavened bread's memorial function: it tastes of the haste of departure and the poverty of slavery. Archaeology has found traces of ancient flatbreads in Levantine contexts; unleavened bread was both the emergency food of hasty travel and the staple of pre-leavening culture. Leaven (<em>chametz</em>) in the NT becomes Paul's metaphor for the old life to be purged (1 Cor 5:6-8: \"clean out the old leaven... for Christ our Passover has been sacrificed\").</p>",
        "4": "<p>\"No leaven shall be seen anywhere in your territory for seven days; and none of the flesh you sacrifice on the evening of the first day shall remain until morning\" — the total leaven-removal from territory: the unleavened-bread feast is not merely a dietary restriction but a spatial cleansing of the entire land. The complete removal of leaven from all visible territory is a communal purification act. The injunction against leaving flesh from the first day overnight echoes the original Passover instructions (Exod 12:10: nothing is to remain until morning) — the meal's completeness-in-one-night signals the definitive quality of the Passover event.</p>",
        "5": "<p>\"You may not sacrifice the Passover within any of your towns that the LORD your God is giving you\" — the centralization restriction: the Passover is removed from household and local practice and concentrated at the central sanctuary. This is the most significant institutional change from Exodus 12 to Deuteronomy 16: what was a household night-meal in Exodus becomes a pilgrimage festival in Deuteronomy. The Second Temple Passover (as described in the Mishnah tractate <em>Pesachim</em>) reflects this centralized structure — pilgrims came to Jerusalem, purchased animals, had them slaughtered in the temple precincts, roasted them in Jerusalem courtyards.</p>",
        "6": "<p>\"Rather, at the place the LORD your God will choose to make his name dwell, there you shall sacrifice the Passover — in the evening at sunset, at the time you came out of Egypt\" — the sunset-timing specified (<em>baerev kevo hashemesh</em>): the Passover begins at evening, consistent with the Hebrew day-structure (evening before morning) and the original Exodus night-event. The time-specification preserves the memorial function: the sacrifice begins as the sun sets, recalling the Exodus departure's darkness, the angel of death's midnight passage, and the dawn departure from Egypt.</p>",
        "7": "<p>\"You shall cook and eat it at the place the LORD your God will choose, and in the morning you shall return to your tents\" — the morning-return permission: unlike the seven-day Feast of Unleavened Bread (v8), the Passover meal itself is a one-night event after which pilgrims may return home. \"Return to your tents\" (<em>ufanita lahaleicha</em>) uses the archaic tent-language for home (a vestige of the wilderness period when Israel lived in tents), becoming a standard idiom for dismissal (cf. 1 Kgs 12:16).</p>",
        "8": "<p>\"For six days you shall eat unleavened bread, and on the seventh day there shall be a solemn assembly for the LORD your God — you shall do no work\" — the seven-day Passover-Unleavened Bread complex concludes with a Sabbath-like assembly (<em>atzeret</em>). The structure mirrors the creation-week pattern: six days of eating/normal activity, the seventh a day of holy assembly. The <em>atzeret</em> (closing assembly) is a day of rest and worship — this pattern recurs at Shavuot (Lev 23:21) and Sukkot (Lev 23:36; Num 29:35). The agricultural festivals are embedded in Sabbath theology: the seventh-day rest extends into the seventh-day feast.</p>",
        "9": "<p>\"Count off seven weeks. Start counting the seven weeks from when the sickle is first put to the standing grain\" — Shavuot (Feast of Weeks) is counted from the beginning of the barley harvest. The fifty-day count (Pentecost = fifty, from Greek <em>pentēkostē</em>, fiftieth) begins at the cutting of the first grain and ends fifty days later at the wheat harvest. The agricultural grounding: Israel counts the weeks between barley harvest and wheat harvest and celebrates at each end. By the Second Temple period, Shavuot had been reinterpreted as the anniversary of the Sinai covenant — the giving of Torah fifty days after the Passover Exodus. Acts 2 takes place on Shavuot: the Spirit is given on the feast of Torah-giving, replacing the external law with the internal Spirit promised by Jeremiah and Ezekiel.</p>",
        "10": "<p>\"Then you shall celebrate the Feast of Weeks to the LORD your God with a freewill offering from your hand — give in proportion to how the LORD your God has blessed you\" — the Shavuot offering is a <em>minat nedavat yadecha</em> (freewill offering of your hand), not a fixed amount but proportional to blessing received. This proportionality principle appears at all three pilgrimage feasts (v17): the covenant's financial obligations scale with YHWH's provision, not as a flat tax. The freewill element acknowledges that the giver's heart-posture matters, not merely the transaction — generosity is the goal, not compliance.</p>",
        "11": "<p>\"You shall rejoice before the LORD your God — you, your son and daughter, your male and female servants, the Levite within your towns, the foreigner, the fatherless, and the widow among you — at the place the LORD your God will choose to make his name dwell\" — the seven-category inclusive celebration: the extended household (children, servants), the dependent class (Levites), the socially marginal (foreign resident, orphan, widow) are all explicitly commanded to rejoice before YHWH at the sanctuary. No member of the covenant community is excluded from the covenant's celebration. This radical inclusivity in Israelite worship contrasts with the stratified access of Egyptian temple religion (ordinary people had no access to the inner sanctuary; only priests approached the deity).</p>",
        "12": "<p>\"Remember that you were a slave in Egypt, and be careful to observe these statutes\" — the Exodus-memory grounds the Feast of Weeks as it grounded the Sabbath (5:15) and the slave-release law (15:15). The agricultural festivals are not merely harvest celebrations but covenant memorials: Israel's abundance in the land is YHWH's gift, understood in light of the Exodus from land-where-they-had-nothing. Gratitude for harvest is gratitude for redemption; the two cannot be separated in Deuteronomy's theological framework.</p>",
        "13": "<p>\"You shall celebrate the Feast of Booths (<em>sukkot</em>) for seven days, when you have gathered in the produce from your threshing floor and your winepress\" — Sukkot is the final harvest festival of the year, the seven-day celebration at the end of the agricultural year (late September-October) when all the grain has been threshed and the wine pressed. The booths (<em>sukkot</em>, temporary shelters) recalled the wilderness wandering when Israel lived in temporary shelters — the most abundant agricultural moment of the year is commemorated by recalling the most vulnerable, landless period of the nation's history. The contrast is theologically deliberate: from wandering in the desert to harvesting the land's abundance.</p>",
        "14": "<p>\"You shall rejoice in your feast — you, your son and daughter, your male and female servants, the Levite, the sojourner, the fatherless, and the widow within your towns\" — the same seven-category inclusivity as Shavuot (v11): every member of the community from the household head to the most marginal is included in the covenant joy. The repetition of this formula across the three feasts establishes it as a liturgical constant: each festival enacts the same covenantal inclusivity. The feast is not a family-only celebration but a community event that deliberately includes those without family or inheritance.</p>",
        "15": "<p>\"For seven days you shall keep the feast to the LORD your God at the place he will choose, for the LORD your God will bless you in all your produce and in all the work of your hands, so that you will be altogether joyful\" — the Sukkot blessing-promise: the harvest abundance is YHWH's blessing, and the joy commanded (<em>vehayita ach sameach</em>, \"and you shall be altogether joyful\") is the covenant community's appropriate response to it. John 7 places Jesus at this feast — the context for his water-of-life announcement (7:37-39). The Sukkot water-drawing ceremony (<em>simchat beit hashoeva</em>) at the Second Temple — celebrated with great joy — is the background for Jesus's invitation: \"If anyone thirsts, let him come to me and drink.\" YHWH's promised blessing becomes Jesus's personal invitation.</p>",
        "16": "<p>\"Three times a year all your males shall appear before the LORD your God at the place he will choose: at the Feast of Unleavened Bread, at the Feast of Weeks, and at the Feast of Booths\" — the three pilgrimage feasts (<em>shalosh regalim</em>): Unleavened Bread (spring, Passover-connected), Weeks (early summer, firstfruits), Booths (autumn, final harvest). The three annual pilgrimages structure the agricultural year around covenant ceremony. Jesus's family pilgrimage to Jerusalem for Passover (Luke 2:41: \"his parents went to Jerusalem every year at the Feast of the Passover\") is the practice of this command. Jesus's own major discourses in John (ch 5 around a feast, ch 6 near Passover, ch 7-8 at Tabernacles, ch 10 at Dedication) follow the pilgrim-feast calendar.</p>",
        "17": "<p>\"Every man shall give as he is able, in proportion to the blessing the LORD your God has given him\" — the proportionality formula closes the three-feast section: each man brings what he can according to YHWH's blessing on him. The principle of proportional giving based on received blessing is consistent throughout the law (10%; the tithe is proportional by definition) and resurfaces in Paul's collection principle (1 Cor 16:2: \"each of you is to put something aside ... as he may prosper\"; 2 Cor 9:7: \"each one must give as he has decided in his heart, not reluctantly or under compulsion, for God loves a cheerful giver\").</p>",
        "18": "<p>\"You shall appoint judges and officials throughout all your towns that the LORD your God is giving you, according to your tribes, and they shall judge the people with righteous judgment\" — the judicial system: local judges and officers in every city, organized by tribal territory. The Deuteronomic judicial reform is substantial: centralize worship at one sanctuary but decentralize justice administration into every community. The complementary institutions prevent both religious and judicial abuse — no single court monopolizes both the divine and human administration of justice. The Levitical priests and the central judge (17:8-12) function as the supreme court; the local judges handle ordinary cases.</p>",
        "19": "<p>\"Do not pervert justice; do not show favoritism; do not accept a bribe — for a bribe blinds the eyes of the wise and twists the words of the righteous\" — the three judicial prohibitions: (1) <em>lo tateh mishpat</em> (pervert justice), (2) <em>lo takir panim</em> (show favoritism, literally \"do not recognize faces\" — do not let social status affect judgment), (3) <em>lo tiqach shochad</em> (accept a bribe). The bribe-wisdom saying is a common ANE proverb: a bribe corrupts even good judgment (<em>iveir einei chachamim</em>, blinds the eyes of the wise). The Egyptian wisdom tradition <em>Instruction of Ptahhotep</em> and the Mesopotamian wisdom texts both warn against judicial bribery; the universality of the corruption problem makes the Deuteronomic prohibition culturally resonant.</p>",
        "20": "<p>\"Justice, and justice alone, you shall pursue (<em>tsedek tsedek tirdof</em>) — so that you may live and possess the land the LORD your God is giving you\" — the famous doubled <em>tsedek</em>: the repetition is the Torah's most emphatic form of intensification. \"Justice, justice\" does not mean two kinds of justice but the absolute, uncompromising pursuit of one justice. The verb <em>radaf</em> (pursue, chase) is hunting vocabulary — pursue justice as one hunts prey, with single-minded urgency. The land-possession condition attached to justice: the land's retention depends on the justice maintained within it. The prophets make this explicit: Amos, Isaiah, Micah, and Jeremiah all connect the land's loss (the Assyrian and Babylonian exiles) to the judicial corruption and social injustice that Deuteronomy 16:18-20 commanded against.</p>",
        "21": "<p>\"You shall not set up any wooden Asherah pole beside the altar of the LORD your God that you build\" — the Asherah prohibition in the context of the pilgrimage-feast commands: the same location (the chosen sanctuary) where Israel celebrates the three feasts must be free of the Canaanite goddess-pole. The Asherah pole (<em>asherah</em>, H842) represented the goddess Asherah, consort of El and/or Baal in Canaanite religion, associated with fertility and blessing. Archaeological finds confirm widespread Asherah veneration in Israel's history — the Kuntillet Ajrud inscriptions (ca. 800 BCE) mention \"YHWH of Samaria and his Asherah,\" indicating some Israelites associated YHWH with an Asherah consort. Deuteronomy's flat prohibition aims to prevent exactly this syncretism at the central sanctuary.</p>",
        "22": "<p>\"And do not erect a sacred stone pillar (<em>matsevah</em>), for the LORD your God hates these\" — the standing-stone prohibition: <em>matsevah</em> (H4676) were upright stones used in Canaanite cult as symbols of divine presence. Interestingly, the patriarchs used standing stones to commemorate theophanic encounters (Gen 28:18; 31:45; 35:14) and these are presented positively in Genesis. Deuteronomy 16:22's prohibition reflects the later covenant concern that standing stones are too easily identified with Canaanite cult practice — whatever their original Israelite usage, they carry the cultural freight of pagan worship. The archaeological record shows standing stones at Israelite cult sites (Hazor, Megiddo, Dan) and their prohibition became increasingly strict in the later prophetic tradition.</p>"
    },
    "17": {
        "1": "<p>\"You shall not sacrifice to the LORD your God an ox or a sheep that has a defect, any serious flaw whatever — that is detestable to the LORD your God\" — the unblemished-sacrifice requirement: <em>mum</em> (H3971, defect/blemish) is a technical cultic term covering any physical imperfection. ANE sacrificial texts from Mesopotamia (ritual texts from Ur III and Old Babylonian periods) and Egypt similarly required unblemished sacrificial animals — the principle that the god deserves the best is universal. What is distinctive in Israel is the reason: YHWH is not manipulated by sacrifice quality (as if a perfect lamb secured his favor more reliably than a blemished one) but the quality requirement expresses the worshiper's acknowledgment of YHWH's worth. Malachi 1:8 makes the honor-logic explicit: would you offer that to your governor?</p>",
        "2": "<p>\"If there is found among you, in any of your towns that the LORD your God is giving you, a man or a woman who does what is evil in the sight of the LORD your God, transgressing his covenant\" — the apostate-investigation law (vv2-7): the gravity of apostasy (<em>la'avor et-berito</em>, transgressing his covenant) is the same as high treason in a suzerainty treaty context — the vassal who defects to another lord has committed the capital offense against the suzerain. The judicial investigation process that follows (v4: diligent inquiry, confirmed truth) prevents mob-action based on rumor and requires due process before any punishment.</p>",
        "3": "<p>\"And has gone and served other gods and bowed down to them, or to the sun or the moon or any of the heavenly host, which I have not commanded\" — the specific apostasy named: sun/moon/star worship (<em>avoda zara</em>) was widespread in the ANE. Mesopotamian astral religion had a developed theology of celestial bodies as deities (Shamash = sun, Sin = moon, Ishtar = Venus). Egyptian solar religion centered on Ra/Amon-Ra. The host of heaven (<em>tseva hashamayim</em>) was a constant temptation for Israel — 2 Kings 21:3-5 records Manasseh's construction of altars to the host of heaven in both the temple courts. The Babylonian exile was in part the consequence of exactly this apostasy (2 Kgs 23:4-12 records Josiah's purge of astral cult items).</p>",
        "4": "<p>\"And you are informed and hear about it, then you shall investigate diligently; and if it is true and confirmed that such a detestable thing has been done in Israel\" — the four-stage judicial process: (1) a report (<em>leacha hachad vehogedu lach</em>), (2) you hear about it, (3) diligent investigation (<em>vedarashta heitev</em>), (4) confirmed truth (<em>vehinei emet nachon haddavar</em>). This is the Deuteronomic legal standard: no one is punished on report alone; the case requires thorough investigation and confirmed evidence. The \"diligent investigation\" standard is the basis for later rabbinic rules of cross-examination and the requirement that witnesses be rigorously tested before their testimony is accepted.</p>",
        "5": "<p>\"Then bring that man or woman to your town gate and stone them to death\" — the town-gate execution: gates (<em>sha'ar</em>) were the civic and legal center of ancient Israelite towns — where judges sat (Deut 16:18; Ruth 4:1-2; Amos 5:12), contracts were witnessed (Ruth 4:11), and public legal acts were performed. Execution at the gate makes the punishment a public covenant act witnessed by the entire community. The public nature was deliberate: Deut 17:13 states the purpose — \"all the people shall hear and be afraid.\" The deterrent function requires publicity.</p>",
        "6": "<p>\"A person shall be put to death only on the testimony of two or three witnesses; no one is to be executed on the testimony of a single witness\" — the two-or-three witnesses rule: this standard (also in Num 35:30; Deut 19:15) becomes a constitutional principle of Jewish legal procedure. The Sanhedrin's rules of capital-case procedure as codified in Tractate Sanhedrin require multiple witnesses and extensive cross-examination. Jesus cites this principle for church discipline (Matt 18:16) and Paul applies it to accusations against elders (1 Tim 5:19). The two-or-three witnesses principle is the OT's most directly cited procedural rule in the NT.</p>",
        "7": "<p>\"The witnesses shall be first to put him to death, and then all the people shall follow. So you shall purge the evil from your midst\" — the witness-first requirement: the eyewitnesses who testified must be the first to throw stones. This requirement does two things: (1) it creates a significant barrier to false testimony — perjurers face executing an innocent person with their own hands; (2) it makes the entire community complicit in the execution, distributing moral responsibility for the covenant's maintenance. The community is not an audience for the court's action but a participant. The purge-formula (<em>uvearta hara miqirbecha</em>) is Deuteronomy's characteristic refrain after capital offenses (13:5; 17:7,12; 19:19; 21:21; 22:21-24; 24:7) — the community's covenant integrity requires removing what corrupts it.</p>",
        "8": "<p>\"If a case arises that is too difficult for your local court — involving disputed homicide, disputed legal rights, or disputed assault — cases of controversy within your towns — then you shall arise and go up to the place that the LORD your God will choose\" — the supreme court provision: three categories of difficult cases — <em>dam ledam</em> (blood to blood, homicide cases), <em>din ledin</em> (legal right to legal right, civil disputes), <em>nega laneqa</em> (affliction to affliction, assault cases). When local courts cannot resolve these, the case goes to the central court at the sanctuary. The term \"arise and go up\" reflects the topography of Jerusalem — one literally went up to the hill-city. This institutional design prevents local-court impasse from generating vendetta and blood-feud.</p>",
        "9": "<p>\"You shall go to the Levitical priests and to the judge who is serving at that time, and you shall consult them, and they shall give you the verdict\" — the central court composition: Levitical priests and a lay judge together. The dual composition (priestly-legal and civic-legal) mirrors the dual authority structure of Deuteronomy throughout — priests handle cultic-religious matters, judges handle civic legal matters. For difficult cases that may combine both dimensions, the joint court is needed. Second Chronicles 19:8-11 describes Jehoshaphat's court reform along these lines: priests and levites for YHWH's matters, senior men for the king's matters. This institution is the ancestor of the Sanhedrin's joint priestly-lay composition.</p>",
        "10": "<p>\"You shall carry out the verdict they announce to you from that place the LORD will choose, and be careful to do all they instruct you\" — the binding verdict requirement: the central court's decision is final and must be implemented. The court's authority derives from its location (\"that place the LORD will choose\") — it is YHWH's own authorized court at YHWH's chosen sanctuary. To reject its ruling is to reject YHWH's judicial authority, which is why (v12) the defiant litigant faces the death penalty.</p>",
        "11": "<p>\"According to the instruction they give you and the verdict they pronounce, you shall act. Do not deviate from what they declare to you, to the right or to the left\" — the right-left non-deviation formula here applied to the court's ruling: the same obedience that is required to YHWH's commandments (5:32; 17:20; 28:14) is required to the central court's verdicts. The court's authority is derivative: it speaks in YHWH's name at YHWH's place, making its rulings functionally equivalent to Torah for the purposes of covenant-community governance.</p>",
        "12": "<p>\"The man who acts arrogantly by refusing to obey the priest who stands to minister before the LORD your God, or the judge — that man shall die. So you shall purge the evil from Israel\" — the capital offense of contempt of court: the willful (<em>zadon</em>, presumption/arrogance) refusal to comply with the central court's ruling is a capital offense because it undermines the covenant community's governance structure. A legal system where verdicts can be ignored with impunity has no authority — the entire judicial institution depends on the enforceability of its rulings. The death penalty for contempt preserves the court's authority at the highest level. The purge-formula closes this section as it did the apostasy section (v7).</p>",
        "13": "<p>\"And all the people shall hear and be afraid, and they will not act presumptuously again\" — the deterrent purpose stated: the public consequence of defying the court (<em>all the people shall hear</em>) produces the fear that prevents repetition (<em>will not act presumptuously again</em>). The deterrent theology of Deuteronomy is systematic: public punishments have a communicative function — they speak to the community about the seriousness of the covenant's claims. The legal system is not only about retributive justice but about the community's ongoing formation in covenant-respect.</p>",
        "14": "<p>\"When you come to the land the LORD your God is giving you and have taken possession and settled in it, and you say, 'I want to set a king over me, like all the nations that are around me'\" — the anticipation of the monarchical request: Moses speaks to a future generation's demand for a king \"like all the nations\" (<em>kechol hagoyim asher sevivotai</em>). The phrase \"like all the nations\" is the key problem — Israel's distinctiveness as YHWH's covenant people is compromised by the desire to be like surrounding kingdoms. When Israel eventually makes this demand (1 Sam 8:5,20), Samuel's response is framed by this Deuteronomy passage: the demand is a rejection of YHWH's kingship (1 Sam 8:7).</p>",
        "15": "<p>\"You may set a king over you — but he must be the one the LORD your God chooses. Set one from among your brothers as king over you; you may not put a foreigner over you, who is not your brother\" — the qualified permission: Israel may have a king, but only on YHWH's terms. The divine-choice of king (<em>asher yivchar YHWH eloheicha bo</em>) anticipates the later election of Saul and David through prophetic designation. The native-king requirement prevents a foreign monarch from ruling Israel — the same kind of foreignness-barrier appears in all ANE royal succession law, but here it has a covenant rationale: the king must be a covenant-party brother, not an outsider with different loyalties.</p>",
        "16": "<p>\"But he must not acquire many horses for himself or send people back to Egypt to get more horses, since the LORD has told you, 'You shall never return that way again'\" — the first anti-kingship restriction: no horse-multiplication. Horses were high-value military assets in the ANE — chariotry was the ancient equivalent of air power, and possession of large horse-chariot forces marked the great powers. Egypt was the primary horse-breeder and exporter of the ancient Near East (horses were not native to Egypt but were bred in the Delta region from Hyksos-era imports). Solomon violated this restriction explicitly: 1 Kings 4:26 (40,000 stalls for horses) and 10:28-29 (horses imported from Egypt and Kue). The return-to-Egypt prohibition echoes the Exodus's directional meaning: forward, not back.</p>",
        "17": "<p>\"He must not take many wives for himself, so his heart is not led astray, nor shall he accumulate excessive silver and gold for himself\" — the second and third anti-kingship restrictions: no wife-multiplication (with the explicit reason — heart-turning to other gods) and no wealth-accumulation. Solomon violated both: 1 Kings 11:3 (700 wives, 300 concubines, \"his wives turned away his heart after other gods\") and 10:14-25 (666 talents of gold per year, silver as common as stone). The law of the king in Deuteronomy 17 reads like a pre-written indictment of the Solomonic monarchy. The three prohibitions (horses, wives, wealth) are the three pillars of ANE royal power — military strength, political alliance-marriages, and economic dominance. Deuteronomy's king law forbids all three as the basis of kingship.</p>",
        "18": "<p>\"When he takes the throne of his kingdom, he shall write for himself in a book a copy of this law, verified by the Levitical priests\" — the law of the royal Torah-copy: the king must personally write his own copy of the Torah, verified by the priestly custodians of the official text. This is the most remarkable royal obligation in the ancient world — no other ANE text requires the king to be a student of divine law. The Egyptian pharaoh was divine and above law; the Mesopotamian king received law from the gods as a gift to give to the people. Deuteronomy's king is a subject of the law, required to know it personally. The word \"copy\" (<em>mishneh</em>, H4932) is the origin of the book's Greek name: <em>deuteronomion</em>, the LXX's translation of \"second law\" or \"copy of the law\" — from which \"Deuteronomy\" derives.</p>",
        "19": "<p>\"It shall be with him, and he shall read in it all the days of his life, that he may learn to fear the LORD his God by keeping all the words of this law and these statutes, and doing them\" — the permanent royal reading program: the Torah-copy accompanies the king throughout his reign, and he reads it continuously (<em>kol yemei chayav</em>, all the days of his life). The purpose is explicitly pedagogical: to learn to fear YHWH (<em>lemaan yilmad liyira</em>) and to keep all the law's words. The king is not the law-giver (as in Mesopotamian royal ideology) but the law's primary student and exemplar. Josiah's response to discovering the Torah scroll (2 Kgs 22:11-13 — he tore his clothes) and his subsequent reform represent this model: a king formed by Torah hearing and reading.</p>",
        "20": "<p>\"So that his heart will not be lifted up above his brothers, and so that he will not turn from the commandment to the right or to the left, and so that he may continue long in his kingdom, he and his children, in Israel\" — the anti-pride purpose: the Torah-reading is designed to prevent the king's heart from being lifted up (<em>lom levavo al echav</em>) above his fellow Israelites. The king is first a brother-Israelite under the same covenant before he is a ruler. The anti-pride language directly addresses the greatest danger of absolute power: the ruler who forgets his creaturely accountability before YHWH and his covenant-level equality with his subjects. The same right-left formula applied to obedience (Deut 5:32; 17:11) applies here to the king's personal covenant-walking. The dynasty-promise (long reign for him and his children) is conditioned on covenant faithfulness — the same condition applied to every Israelite throughout Deuteronomy.</p>"
    }
}


def main():
    existing = load_comm("mkt-context", "deuteronomy")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, DEUT)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-context", "deuteronomy", existing)
    print(f"Deuteronomy mkt-context: {after} verse entries total (+{after - before} new)")
    for ch in ["14", "15", "16", "17"]:
        total = {"14": 29, "15": 23, "16": 22, "17": 20}[ch]
        present = len(existing.get(ch, {}))
        missing = [str(i) for i in range(1, total + 1) if str(i) not in existing.get(ch, {})]
        print(f"  Ch {ch}: {present}/{total} — missing: {missing if missing else 'none'}")


if __name__ == "__main__":
    main()
